class JWTClaims(BaseModel):
    sub: str
    scope: str
    exp: int
    iat: Optional[int] = None
    required_fields: Tuple[str, ...] = Field(default=('sub', 'scope', 'exp'), frozen=True)

    def audit_completeness(self) -> Dict[str, bool]:
        missing = []
        for field in self.required_fields:
            if not getattr(self, field, None):
                missing.append(field)
        if missing:
            print(f'🚨 MISSING AUTH CLAIMS: {missing}')
        return {'complete': len(missing) == 0, 'missing': missing}

