from typing import Literal
VALID_SCOPES = ['read:users', 'write:users', 'admin:users']

class CoercedScope(BaseModel):
    scopes: List[str]

    @validator('scopes')
    def coerce_scopes(cls, v):
        coerced = []
        for scope in v:
            # Exact match first
            if scope in VALID_SCOPES:
                coerced.append(scope)
            else:
                # Semantic fallback (simplified)
                if 'read' in scope.lower():
                    coerced.append('read:users')
                elif 'write' in scope.lower():
                    coerced.append('write:users')
                else:
                    coerced.append('read:users')  # Safe default
                print(f'⚠️  COERCED {scope} -> {coerced[-1]}')
        return coerced

response = client.messages.create(
    response_model=CoercedScope,
    messages=[{'role': 'user', 'content': 'Permissions: read_users, super_admin'}]
)

class RoleHierarchy(BaseModel):
    name: str
    permissions: List[str]
    inherited: Optional['RoleHierarchy'] = None
    _depth: int = 0

    @validator('inherited', pre=True, always=True)
    def validate_depth(cls, v, values):
        if values.get('_depth', 0) > 3:
            print('🚫 MAX ROLE DEPTH EXCEEDED')
            return None
        if v is not None:
            v._depth = values['_depth'] + 1
        return v

# Recursive validation works safely
hierarchy = client.messages.create(
    model='gpt-4o',
    response_model=RoleHierarchy,
    messages=[{'role': 'user', 'content': 'Role: admin {permissions: ["*"], inherited: {user}}'}]
)

